    }    else if (value is CreateAlarmCommandDto) {
      buffer.putUint8(131);
      writeValue(buffer, value.encode());
    }    else if (value is UpdateAlarmCommandDto) {
      buffer.putUint8(132);
      writeValue(buffer, value.encode());
    }    else if (value is AlarmHistoryDto) {
      buffer.putUint8(133);
      writeValue(buffer, value.encode());
    }    else if (value is ReliabilitySnapshotDto) {
      buffer.putUint8(134);
      writeValue(buffer, value.encode());
    }    else if (value is TestAlarmResultDto) {
      buffer.putUint8(135);
      writeValue(buffer, value.encode());
    }    else if (value is SoundProfileDto) {
      buffer.putUint8(136);
      writeValue(buffer, value.encode());
    }    else if (value is TemplateDto) {
      buffer.putUint8(137);
      writeValue(buffer, value.encode());
    }    else if (value is BackupImportResultDto) {
      buffer.putUint8(138);
      writeValue(buffer, value.encode());
    }    else if (value is OemGuidanceDto) {
      buffer.putUint8(139);
      writeValue(buffer, value.encode());
    }    else if (value is StatsSummaryDto) {
      buffer.putUint8(140);
      writeValue(buffer, value.encode());
    }    else if (value is StatsTrendPointDto) {
      buffer.putUint8(141);
      writeValue(buffer, value.encode());
    }    else if (value is OnboardingReadinessDto) {
      buffer.putUint8(142);
      writeValue(buffer, value.encode());
    } else {
      super.writeValue(buffer, value);
    }
  }

  @override
  Object? readValueOfType(int type, ReadBuffer buffer) {
    switch (type) {
      case 129: 
        return TriggerDto.decode(readValue(buffer)!);
      case 130: 
        return AlarmPlanDto.decode(readValue(buffer)!);
      case 131: 
        return CreateAlarmCommandDto.decode(readValue(buffer)!);
      case 132: 
        return UpdateAlarmCommandDto.decode(readValue(buffer)!);
      case 133: 
        return AlarmHistoryDto.decode(readValue(buffer)!);
      case 134: 
