      case 136: 
        return SoundProfileDto.decode(readValue(buffer)!);
      case 137: 
        return TemplateDto.decode(readValue(buffer)!);
      case 138: 
        return BackupImportResultDto.decode(readValue(buffer)!);
      case 139: 
        return OemGuidanceDto.decode(readValue(buffer)!);
      case 140: 
        return StatsSummaryDto.decode(readValue(buffer)!);
      case 141: 
        return StatsTrendPointDto.decode(readValue(buffer)!);
      case 142: 
        return OnboardingReadinessDto.decode(readValue(buffer)!);
      default:
        return super.readValueOfType(type, buffer);
